812	  /**
813	   * Utility functions for receipt calculations.
814	   */
815	  export namespace utils {
816	    /**
817	     * Filters people based on assignment and search value.
818	     * @param people - All people (receipt user IDs - ULIDs)
819	     * @param assignedPeople - People already assigned (receipt user IDs - ULIDs)
820	     * @param searchValue - Optional search string to filter by display name
821	     * @returns Filtered people not assigned and matching search (if provided)
822	     */
823	    export function filterPeople(
824	      people: readonly string[],
825	      assignedPeople: readonly string[],
826	      searchValue?: string
827	    ): string[] {
828	      if (searchValue) {
829	        // Note: searchValue doesn't make sense with numeric IDs, but kept for API compatibility
830	        // In practice, this would need user data to search by name
831	        return people.filter((person) => !assignedPeople.includes(person));
832	      }
833	
834	      return people.filter((person) => !assignedPeople.includes(person));
835	    }
