837	    /**
838	     * Formats the percentage that a partial value represents of a total value.
839	     * Returns a locale-aware formatted percentage string (e.g., "25.50%").
840	     *
841	     * The calculation is: (partial / total) * 100, then formatted using Intl.NumberFormat
842	     * with the 'percent' style for proper locale-aware display.
843	     *
844	     * Uses Decimal.js for precise division to avoid floating-point rounding errors.
845	     * If the total is zero or negative, returns "0%" and logs a warning.
846	     *
847	     * @param partial - The partial value to calculate the percentage for (as a Decimal instance)
848	     * @param total - The total value to use as the denominator (as a Decimal instance)
849	     * @returns A formatted percentage string (e.g., "25.50%", "0%"). Returns "0%" if total is zero or negative.
850	     *
851	     * @example
852	     * ```ts
853	     * // Format what percentage $25.50 is of $100.00
854	     * const percentage = calculations.utils.formatPercentage(
855	     *   new Decimal(25.50),
856	     *   new Decimal(100.00)
857	     * );
858	     * // Returns: "25.5%"
859	     *
860	     * // Format what percentage $33.33 is of $99.99
861	     * const percentage = calculations.utils.formatPercentage(
862	     *   new Decimal(33.33),
863	     *   new Decimal(99.99)
864	     * );
865	     * // Returns: "33.33%"
866	     *
867	     * // Returns "0%" if total is zero (logs warning)
868	     * const percentage = calculations.utils.formatPercentage(
869	     *   new Decimal(10),
870	     *   new Decimal(0)
871	     * );
872	     * // Returns: "0%"
873	     * ```
874	     */
875	    export function formatPercentage(partial: Decimal, total: Decimal): string {
876	      // TODO internationalize
877	      const formatter = new Intl.NumberFormat('en-US', {
878	        style: 'percent',
879	        maximumFractionDigits: 2,
880	      });
881	
882	      if (!total.gt(0)) {
883	        // TODO use observability library to log this
884	        console.warn('Total is zero');
885	        return formatter.format(0);
886	      }
887	
888	      return formatter.format(Decimal.div(partial, total).toNumber());
889	    }
890	  }
891	}
